1	`timescale 1ns / 1ns
2	
3	// Propagate between 5 and 512 resonators, two clock cycles per resonator.
4	// Timing of input drive signal, and output position signal, are relative
5	// to the start pulse.
6	
7	// Executes z * v_o = v_o + (a-1) * v_o + v_i
8	// where all quantities are complex, and a is the pole location.  Nominal
9	// configuration for second-order low-pass uses real number input, and
10	// the imaginary component of v_o is the output.  More precisely, it
11	// executes z * v_o = v_o + (wd * v_o + v_i) * 4^(scale-9)
12	// where wd = (a-1) * 4^(7-scale) and scale is between 0 and 7.
13	// The low-frequency gain in the low-pass configuration is -imag(1/wd)
14	
15	// Considered z * v_o = v_o + (a-1) * (v_o + v_i), which has a simpler
16	// expression for gain, but rejected it because that would break the
17	// real/imaginary setup of a low-pass filter.
18	
19	// The drive signal for mode 1, using coefficients kept at memory locations
20	// 2 and 3, needs to show up 12 and 13 cycles after the start pulse.
21	// The output will arrive 4 cycles after the drive.  These relations still
22	// hold if they pass over the following start pulse; everything is circular.
23	// But the pipeline length of 10 means the minimum number of resonators is 5.
24	// Of course, just because a resonator is in memory and gets processed,
25	// doesn't mean you have to feed it non-zero drive, or look at the result.
26	
27	// Two 18x18 multipliers here; dwarfed by the multipliers used to
28	// compute dot products.  One set to convert physical excitation
29	// sources to the per-mode drive signal, and another set to convert
30	// from the abstract mode coordinates to the physical responses
31	// (cavity electrical mode frequency shifts).
32	
33	// The size and speed of this module is such that it might be able to
34	// handle simulation of a whole cryomodule at once (8 cavities) in the
35	// XC7A200T of an AC701 board.
36	module resonator(
37		input clk,
38		input start,  // provide every (number of modes)*2 clock cycles
39		input signed [17:0] drive,
40		output signed [17:0] position,
41		output clip,
42		(* external *)
43		input [20:0] prop_const,  // external
44		(* external *)
45		output [9:0] prop_const_addr  // external
46	);
47	
48	// pcw sets the size of state and coefficient memory.
49	// The number of resonator modes processed is 2^(pcw-1), since
50	// one mode takes two memory locations and two cycles.
51	// The time between start pulses should not exceed 2^pcw cycles.
52	// For now pcw must match width of prop_const_addr.
53	parameter pcw = 10;
54	
55	reg [pcw-1:0] pc=0;
56	always @(posedge clk) pc <= start ? 0 : pc+1;
57	wire iq = pc[0];
58	
59	// Delay from register read to register write
60	wire [pcw-1:0] pc_d;
61	reg_delay #(.dw(pcw),.len(11))
62		pc_del(.clk(clk), .reset(1'b0), .gate(1'b1), .din(pc), .dout(pc_d));
63	
64	// State vector memory
65	// Scaled fixed-point such that full-scale is 1.0
66	wire signed [35:0] ab_out0;
67	wire signed [35:0] ab_in;  // computed later
68	dpram #(.dw(36), .aw(pcw)) ab(.clka(clk), .clkb(clk),
69		.addra(pc_d), .dina(ab_in), .wena(1'b1),
70		.addrb(pc), .doutb(ab_out0));
71	
72	// Result from state propagation constant memory (host-writable)
73	wire signed [17:0] wd_out0 = prop_const[17:0];
74	wire [2:0] scale0 = prop_const[20:18];
75	assign prop_const_addr = pc;
76	
77	// Pipeline
78	reg signed [35:0] ab_out=0, ab_out1=0;
79	reg signed [17:0] wd_out=0, wd_out1=0;
80	reg [2:0] scale=0, scale1=0;
81	always @(posedge clk) begin
82		ab_out1 <= ab_out0;  ab_out <= ab_out1;
83		wd_out1 <= wd_out0;  wd_out <= wd_out1;
84		scale1  <= scale0;   scale  <= scale1;
85	end
86	
87	// Complex multiply, same as matrix [-d k;-k -d]
88	wire signed [17:0] mul_result;
89	complex_mul mul(.clk(clk), .gate_in(1'b1), .iq(iq),
90		.x(ab_out[35:18]), .y(wd_out), .z(mul_result));
91	// I want to take SAT out of complex_mul to save a useless
92	// pipelining step or two, see sub_mul in lp1.v
93	
94	// Add in the drive term, itself a dot-product of excitation sources
95	reg signed [18:0] foo_result=0;
96	always @(posedge clk) foo_result <= mul_result + drive;
97	
98	// Binary scaling
99	wire [2:0] scale_d;
100	reg_delay #(.dw(3),.len(5))
101		sc_del(.clk(clk), .reset(1'b0), .gate(1'b1), .din(scale), .dout(scale_d));
102	
103	reg signed [32:0] shf_result=0;
104	always @(posedge clk) case (scale_d)
105		3'd0: shf_result <= foo_result;
106		3'd1: shf_result <= foo_result <<< 2;
107		3'd2: shf_result <= foo_result <<< 4;
108		3'd3: shf_result <= foo_result <<< 6;
109		3'd4: shf_result <= foo_result <<< 8;
110		3'd5: shf_result <= foo_result <<< 10;
111		3'd6: shf_result <= foo_result <<< 12;
112		3'd7: shf_result <= foo_result <<< 14;
113	endcase
114	
115	// Combine original state vector with delta
116	wire signed [35:0] ab_del_out;
117	reg_delay #(.dw(36),.len(6))
118		ab_del(.clk(clk), .reset(1'b0), .gate(1'b1), .din(ab_out), .dout(ab_del_out));
119	reg signed [36:0] sum_result=0;
120	always @(posedge clk) sum_result <= ab_del_out + shf_result;
121	
122	// Saturate result
123	`define SAT(x,old,new) ((~|x[old:new] | &x[old:new]) ? x[new:0] : {x[old],{new{~x[old]}}})
124	reg signed [35:0] sat_result=0;
125	reg clip_r=0;
126	always @(posedge clk) begin
127		sat_result <= `SAT(sum_result,36,35);
128		clip_r <= ~(~|sum_result[36:35] | &sum_result[36:35]);
129	end
130	`undef SAT
131	
132	assign ab_in = sat_result;
133	assign position = sat_result[35:18];
134	assign clip = clip_r;
135	
136	endmodule
