`timescale 1ns / 1ns

// Propagate between 5 and 512 resonators, two clock cycles per resonator.
// Timing of input drive signal, and output position signal, are relative
// to the start pulse.

// Executes z * v_o = v_o + (a-1) * v_o + v_i
// where all quantities are complex, and a is the pole location.  Nominal
// configuration for second-order low-pass uses real number input, and
// the imaginary component of v_o is the output.  More precisely, it
// executes z * v_o = v_o + (wd * v_o + v_i) * 4^(scale-9)
// where wd = (a-1) * 4^(7-scale) and scale is between 0 and 7.
// The low-frequency gain in the low-pass configuration is -imag(1/wd)

// Considered z * v_o = v_o + (a-1) * (v_o + v_i), which has a simpler
// expression for gain, but rejected it because that would break the
// real/imaginary setup of a low-pass filter.

// The drive signal for mode 1, using coefficients kept at memory locations
// 2 and 3, needs to show up 12 and 13 cycles after the start pulse.
// The output will arrive 4 cycles after the drive.  These relations still
// hold if they pass over the following start pulse; everything is circular.
// But the pipeline length of 10 means the minimum number of resonators is 5.
// Of course, just because a resonator is in memory and gets processed,
// doesn't mean you have to feed it non-zero drive, or look at the result.

// Two 18x18 multipliers here; dwarfed by the multipliers used to
// compute dot products.  One set to convert physical excitation
// sources to the per-mode drive signal, and another set to convert
// from the abstract mode coordinates to the physical responses
// (cavity electrical mode frequency shifts).

// The size and speed of this module is such that it might be able to
// handle simulation of a whole cryomodule at once (8 cavities) in the
// XC7A200T of an AC701 board.
module resonator(
	input clk,
	input start,  // provide every (number of modes)*2 clock cycles
	input signed [17:0] drive,
	output signed [17:0] position,
	output clip,
	(* external *)
	input [20:0] prop_const,  // external
	(* external *)
	output [9:0] prop_const_addr  // external
);

// pcw sets the size of state and coefficient memory.
// The number of resonator modes processed is 2^(pcw-1), since
// one mode takes two memory locations and two cycles.
// The time between start pulses should not exceed 2^pcw cycles.
// For now pcw must match width of prop_const_addr.
parameter pcw = 10;

reg [pcw-1:0] pc=0;
always @(posedge clk) pc <= start ? 0 : pc+1;
wire iq = pc[0];

// Delay from register read to register write
wire [pcw-1:0] pc_d;
reg_delay #(.dw(pcw),.len(11))
	pc_del(.clk(clk), .reset(1'b0), .gate(1'b1), .din(pc), .dout(pc_d));

// State vector memory
// Scaled fixed-point such that full-scale is 1.0
wire signed [35:0] ab_out0;
wire signed [35:0] ab_in;  // computed later
dpram #(.dw(36), .aw(pcw)) ab(.clka(clk), .clkb(clk),
	.addra(pc_d), .dina(ab_in), .wena(1'b1),
	.addrb(pc), .doutb(ab_out0));

// Result from state propagation constant memory (host-writable)
wire signed [17:0] wd_out0 = prop_const[17:0];
wire [2:0] scale0 = prop_const[20:18];
assign prop_const_addr = pc;

// Pipeline
reg signed [35:0] ab_out=0, ab_out1=0;
reg signed [17:0] wd_out=0, wd_out1=0;
reg [2:0] scale=0, scale1=0;
always @(posedge clk) begin
	ab_out1 <= ab_out0;  ab_out <= ab_out1;
	wd_out1 <= wd_out0;  wd_out <= wd_out1;
	scale1  <= scale0;   scale  <= scale1;
end

// Complex multiply, same as matrix [-d k;-k -d]
wire signed [17:0] mul_result;
complex_mul mul(.clk(clk), .gate_in(1'b1), .iq(iq),
	.x(ab_out[35:18]), .y(wd_out), .z(mul_result));
// I want to take SAT out of complex_mul to save a useless
// pipelining step or two, see sub_mul in lp1.v

// Add in the drive term, itself a dot-product of excitation sources
reg signed [18:0] foo_result=0;
always @(posedge clk) foo_result <= mul_result + drive;

// Binary scaling
wire [2:0] scale_d;
reg_delay #(.dw(3),.len(5))
	sc_del(.clk(clk), .reset(1'b0), .gate(1'b1), .din(scale), .dout(scale_d));

reg signed [32:0] shf_result=0;
always @(posedge clk) case (scale_d)
	3'd0: shf_result <= foo_result;
	3'd1: shf_result <= foo_result <<< 2;
	3'd2: shf_result <= foo_result <<< 4;
	3'd3: shf_result <= foo_result <<< 6;
	3'd4: shf_result <= foo_result <<< 8;
	3'd5: shf_result <= foo_result <<< 10;
	3'd6: shf_result <= foo_result <<< 12;
	3'd7: shf_result <= foo_result <<< 14;
endcase

// Combine original state vector with delta
wire signed [35:0] ab_del_out;
reg_delay #(.dw(36),.len(6))
	ab_del(.clk(clk), .reset(1'b0), .gate(1'b1), .din(ab_out), .dout(ab_del_out));
reg signed [36:0] sum_result=0;
always @(posedge clk) sum_result <= ab_del_out + shf_result;

// Saturate result
`define SAT(x,old,new) ((~|x[old:new] | &x[old:new]) ? x[new:0] : {x[old],{new{~x[old]}}})
reg signed [35:0] sat_result=0;
reg clip_r=0;
always @(posedge clk) begin
	sat_result <= `SAT(sum_result,36,35);
	clip_r <= ~(~|sum_result[36:35] | &sum_result[36:35]);
end
`undef SAT

assign ab_in = sat_result;
assign position = sat_result[35:18];
assign clip = clip_r;

endmodule

`timescale 1ns / 1ns
`define AUTOMATIC_self
`define AUTOMATIC_decode
`define AUTOMATIC_piezo_couple
`define AUTOMATIC_compr
`define AUTOMATIC_amp_lp
`define AUTOMATIC_cav_elec
`define AUTOMATIC_prng
`define AUTOMATIC_a_cav
`define AUTOMATIC_a_for
`define AUTOMATIC_a_rfl
`include "station_auto.vh"

// Single cavity emulator
// Now that cav_elec is working, this idea extends easily to multiple
// cavities sharing mechanical dynamics, but the port count balloons.
// Functionality overlaps some with cav_elec_tb.v
// Address map imported via cav_elec:
//    1-2     LO DDS
//    8-11    prompt forward and reflected setup
//   16-23    mode 0 cav_mode registers
//   24-31    mode 1 cav_mode registers
//   32-39    mode 2 cav_mode registers
// 2048-4095  mode 0 mechanical coupling in and out
// 4096-6143  mode 1 mechanical coupling in and out
// 6144-8191  mode 3 mechanical coupling in and out
// to which we add here:
//    3-4     beam timing
//    65      amplifier bandwidth
//  129-131   ADC offsets
//    159     PRNG enable
//  160-191   PRNG A initialization
//  192-223   PRNG B initialization
// 1024-2047  resonator
// 8192-9215  piezo coupling to mechanical system
// 9216-10239 noise coupling to mechanical system

// XXX want some way to view mechanical state
// Do I want to read out a piezo current, that depends on mechanics?
// Do we want to add coarse cable drift, or are phase shifts enough?
// 11999 LUTs and 34 DSP48E1 in XC7Axx
module station(
  input clk,
  input iq,
  input signed [17:0] drive,  // not counting beam
  input start,
  input signed [17:0] mech_x,
  input signed [17:0]  piezo,
  input start_outer,
  // Output ADCs at 20 MHz IF
  output signed [15:0] a_field,
  output signed [15:0] a_forward,
  output signed [15:0] a_reflect,
  output signed [17:0] cav_eig_drive,
  output signed [17:0] piezo_eig_drive,
  input [11:0] beam_timing,
  // Local Bus for simulator configuration
  `AUTOMATIC_self
);
`undef AUTOMATIC_self

`AUTOMATIC_decode

// Virtual Piezo
// Couple the piezo to mechanical drive
(* lb_automatic *)
outer_prod piezo_couple  // auto
	(.clk(clk), .start(start_outer), .x(piezo), .result(piezo_eig_drive),
	 `AUTOMATIC_piezo_couple
);

// Amplifier compression step
wire signed [17:0] compress_out;
(* lb_automatic *)
a_compress compr // auto
	(.clk(clk), .iq(iq), .d_in(drive), .d_out(compress_out),
	`AUTOMATIC_compr);
reg signed [17:0] compress_out_d=0;
always @(posedge clk) compress_out_d <= compress_out;
wire signed [17:0] ampf_in = compress_out_d; // was drive

// Amplifier low-pass filter, maximum bandwidth 3.75 MHz
wire signed [17:0] amp_out1;
(* lb_automatic *)
lp_pair #(.shift(2)) amp_lp  // auto
	(.clk(clk), .drive(ampf_in), .drive2(24'b0), .res(amp_out1), `AUTOMATIC_amp_lp);

// Configure number of modes processed
// I don't make it host-settable (at least not yet),
// because of its interaction with interp_span.
parameter n_mech_modes = 7;
parameter n_cycles = n_mech_modes * 2;
parameter interp_span = 4;  // ceil(log2(n_cycles))
parameter mode_count = 3;

// Allow tweaks to the cavity electrical eigenmode time scale
parameter mode_shift=18;

// Control how much frequency shifting is possible with mechanical displacement
parameter df_scale=0;     // see cav_freq.v

// Instantiate one cavity
wire signed [17:0] field, forward, reflect;
(* lb_automatic *)
cav_elec #(.mode_shift(mode_shift), .interp_span(interp_span), .df_scale(df_scale), .mode_count(mode_count)) cav_elec // auto
	(.clk(clk),
	.iq(iq), .drive(amp_out1), .beam_timing(beam_timing),
	.field(field), .forward(forward), .reflect(reflect),
	.start(start), .mech_x(mech_x), .eig_drive(cav_eig_drive),
	`AUTOMATIC_cav_elec
);

// Pseudorandom number subsystem
wire [31:0] rnda, rndb;
(* lb_automatic *)
prng prng  // auto
	(.clk(clk), .rnda(rnda), .rndb(rndb),
	`AUTOMATIC_prng);

// ADCs themselves
// Offsets could be allowed to drift
(* lb_automatic *)
adc_em #(.del(1)) a_cav // auto
	(.clk(clk), .strobe(iq), .in(field),   .rnd(rnda[12: 0]), .adc(a_field), `AUTOMATIC_a_cav);
(* lb_automatic *)
adc_em #(.del(1)) a_for // auto
	(.clk(clk), .strobe(iq), .in(forward), .rnd(rnda[25:13]), .adc(a_forward), `AUTOMATIC_a_for);
(* lb_automatic *)
adc_em #(.del(1)) a_rfl // auto
	(.clk(clk), .strobe(iq), .in(reflect), .rnd(rndb[12: 0]), .adc(a_reflect), `AUTOMATIC_a_rfl);

`undef AUTOMATIC_prng
endmodule

`timescale 1ns / 1ns
`define AUTOMATIC_self
`define AUTOMATIC_decode
`define AUTOMATIC_noise_couple
`define AUTOMATIC_resonator
`define AUTOMATIC_prng
`include "cav_mech_auto.vh"

module cav_mech(
  input clk,
  input start_eig,
  input start_outer,
  output signed [17:0] mech_x,
  output signed [17:0] noise_eig_drive,
  input signed [17:0] eig_drive,
  // Output status
  output res_clip,
  `AUTOMATIC_self
);
`undef AUTOMATIC_self

`AUTOMATIC_decode

parameter n_mech_modes = 7;
parameter n_cycles = n_mech_modes * 2;

// Couple randomness to mechanical drive
wire signed [17:0] environment;  // filled in later
(* lb_automatic *)
outer_prod noise_couple  // auto
	(.clk(clk), .start(start_outer), .x(environment), .result(noise_eig_drive),
	 `AUTOMATIC_noise_couple
);

// Instantiate the mechanical resonance computer
(* lb_automatic *)
resonator resonator // auto
  (.clk(clk), .start(start_eig),
	 .drive(eig_drive),
	 .position(mech_x), .clip(res_clip),
	 `AUTOMATIC_resonator
);
// Pseudorandom number subsystem
wire [31:0] rnda, rndb;

(* lb_automatic *)
prng prng  // auto
  (.clk(clk), .rnda(rnda), .rndb(rndb),
   `AUTOMATIC_prng);

// Create a white noise term for environment
// This is a strangely-scaled CIC filter
// Each iteration adds a variance of 12, consuming 6 bits of PRNG
// Result has variance of n_cycles*12, mean of 0, possible peak n_cycles*7
// e.g. if n_cycles=14, std.dev.=12.96, peak=98, peak/rms=7.56
reg signed [11:0] noise_accum=0, noise_1=0, noise_out=0;
always @(posedge clk) begin
	 noise_accum <= noise_accum + rndb[2:0] - rndb[5:3];
	 if (start_eig) begin
		  noise_1 <= noise_accum;
		  noise_out <= noise_1-noise_accum;
	 end
end
assign environment = noise_out;

`undef AUTOMATIC_prng
endmodule // cav_mech

`timescale 1ns / 1ns

// Time-interleaved pair of low-pass filters
// Larry Doolittle, LBNL, May 2014
// Upper six drive bits in drive2 are for short-pulse
// contributions from the beam; don't use them CW or this accumulator
// will overflow.  To avoid instant overflows with such wide input,
// shift should be > 6.
module lp_pair(
	input clk,
	input signed [17:0] drive,
	input signed [23:0] drive2,
	(* external *)
	input signed [17:0] bw,  // external
	output signed [17:0] res
);

parameter shift=18;  // maximum bandwidth is f_clk/2/2^shift/(2*pi)
// e.g., with f_clk=188.6 MHz, shift=18, max BW is 57.2 Hz.

// Note that as the bandwidth is turned down from that maximum,
// so too should the signal level of the drive.  We don't have
// overflow detection programmed in here.

// 1/(1+(1-a)*z^{-2}) for small a behaves a lot like 1/(1+(1-a)*z^{-1})

// Scalar multiply field by the desired bandwidth, sets decay time
reg signed [17+shift:0] state=0, sum1=0;
reg signed [35:0] decay1=0;
wire signed [17:0] decay1s = decay1[34:17];
reg signed [17:0] decay2=0, decay3=0;
wire signed [18:0] diff = drive - $signed(state[17+shift:shift]);
always @(posedge clk) begin
	decay1 <= $signed(diff[18:1]) * bw;
	decay2 <= decay1s;
	decay3 <= decay2;
	sum1 <= state + drive2;
	state <= sum1 + decay3;
end

assign res = state[17+shift:shift];

endmodule

`timescale 1ns / 1ns
module adc_em(
	input clk,
	input strobe,
	input signed [17:0] in,
	input [12:0] rnd,  // randomness
	(* external *)
	input signed [9:0] offset,  // external
	output signed [15:0] adc
);

parameter del=1;

// We wish to emulate a LTC2175-like ADC, 14-bit with 73.0 dB SNR.
// 14-bit full-scale sine wave has rms value 2^13/sqrt(2) = 5793.
// So the noise level is -73.0 dB from there, or 1.30 bits rms.
// One random bit flickering has mean 1/2 and variance 1/4, so to
// emulate a variance of 1.30^2, we need 6.76 (really 20.3) such bits.

// Adding together 6 bits would give a range of +/- 3 quanta, and
// and an rms of 1.22, for a peak/rms ratio of 2.45, pretty pathetic.

// Adding together 26 bits would give a range of +/- 13 quanta,
// and an rms of 2.55, for a peak/rms ratio of 5.10, plausible.
// Divide that result by two to get the desired rms of 1.27.

// Since this module is designed to be double-clocked, take in
// just 13 bits of randomness per cycle.

// The nominal ADC at the moment is 14-bits, so when we're done,
// pad to the right with two more bits, to fit the future-proof
// 16-bit interface.

// Get random bits from TT800 or equivalent, combine them here to
// get the required Additive White Gaussian Noise.  By construction,
// when each random input bit is fair, the mean of awgn is zero.
// Also, if the PRNG stalls, the AWGN term goes immediately to zero.
wire [12:0] p = rnd;
reg [3:0] bit_cnt=0, bit_cnt_d=0;
reg signed [4:0] awgn=0;
always @(posedge clk) begin
	bit_cnt <= p[0]+p[1]+p[2]+p[3]+p[4]+p[5]+p[6]+p[7]+p[8]+p[9]+p[10]+p[11]+p[12];
	bit_cnt_d <= bit_cnt;
	awgn <= bit_cnt - bit_cnt_d;
end

// Combine "real" voltage, AWGN, and offset
`define SAT(x,old,new) ((~|x[old:new] | &x[old:new]) ? x[new:0] : {x[old],{new{~x[old]}}})
reg signed [18:0] sum=0;
always @(posedge clk) sum <= in + (awgn <<< 3) + offset;
wire signed [14:0] sum_trunc = sum[18:4];
reg signed [13:0] sat=0;
always @(posedge clk) sat <= `SAT(sum_trunc,14,13);
`undef SAT

// Adjustable delay
wire signed [13:0] dval;
reg_delay #(.dw(14), .len(del))
	dd(.clk(clk), .reset(1'b0), .gate(strobe), .din(sat), .dout(dval));

assign adc = {dval,2'b0};

endmodule

