32	reg_delay #(.dw(1), .len(2))
33		zd(.clk(clk), .reset(1'b0), .gate(1'b1), .din(start), .dout(grab));
34	
35	assign k_out_addr = pc;
36	
37	// As always, demand that k is not full-scale negative
38	reg signed [17:0] x_hold=0;
39	reg signed [35:0] mul1=0;
40	wire signed [17:0] mul1s=mul1[34:17];
41	reg signed [17:0] k_out1=0, mul2=0, mul3=0;
42	always @(posedge clk) begin
43		if (grab) x_hold <= x;
44		k_out1 <= k_out;
45		mul1 <= k_out1 * x_hold;
46		mul2 <= mul1s;
