endmodule

module simple_cic(
	input clk,
	input sample,
	input signed [17:0] cosd,
	input signed [17:0] sind,
	input signed [15:0] in,
	output signed [17:0] out_i,
	output signed [17:0] out_q
);
reg signed [23:0] acc_i=0, acc_q=0;
reg signed [23:0] hld_i=0, hld_q=0;
reg signed [23:0] cic_i=0, cic_q=0;
wire signed [33:0] cos_prod = in*cosd;
wire signed [33:0] sin_prod = in*sind;
always @(posedge clk) begin
	acc_i <= acc_i + (cos_prod>>>15);
	acc_q <= acc_q + (sin_prod>>>15);
	if (sample) begin
		hld_i <= acc_i;  cic_i <= acc_i - hld_i;
		hld_q <= acc_q;  cic_q <= acc_q - hld_q;
	end
end
assign out_i = $signed(cic_i[23:2])/33;
assign out_q = $signed(cic_q[23:2])/33;
endmodule

`timescale 1ns / 1ns

module cav_freq(
	input clk,
	input signed [17:0] fine,
	// getting the following control into the address map is the
	// whole point of this module:
	(* external *)
	input signed [27:0] coarse_freq, // external
	output signed [27:0] out
);

// valid range of df_scale is 0 to 9, but one has to be increasingly
// concerned about overflow.  The Pro tip about the range of coarse
// frequency in cav_elec.v is implicitly sensitive to df_scale.
parameter df_scale=0;

reg signed [29:0] out_r=0;
always @(posedge clk) out_r <= (fine<<<df_scale) + (coarse_freq<<<2) + 2;
assign out = out_r[29:2];

endmodule

`timescale 1ns / 1ns

// Encapsulation of a register delay, z^{-n} in DSP-speak
// Properly handles odd-ball special cases like len==0
module reg_delay #(
	parameter dw=16,  // Width of data
	parameter len=4   // Cycles to delay
) (
	input clk,  // Rising edge clock input; all logic is synchronous in this domain
	input reset,  // Please tie to 0 if you can; see below
	input gate,  // Enable processing
	input [dw-1:0] din,  // Input data
	output [dw-1:0] dout  // Output data
);

// When used in a Xilinx chip, ideally this logic is turned into
// a bunch of SRL16 shift registers or similar.  That works only if
// our reset port is tied to 1'b0 at instantiation site.
generate if (len > 1) begin: usual
	reg [dw*len-1:0] shifter=0;
	always @(posedge clk) begin
		if (gate) shifter <= {shifter[dw*len-1-dw:0],din};
		if (reset) shifter <= 0;
	end
	assign dout = shifter[dw*len-1:dw*len-dw];
end else if (len > 0) begin: degen1
	reg [dw*len-1:0] shifter=0;
	always @(posedge clk) begin
		if (gate) shifter <= din;
		if (reset) shifter <= 0;
	end
	assign dout = shifter[dw*len-1:dw*len-dw];
end else if (len == 0) begin: degen0
	assign dout = din;
end else begin: bad
	assign dout = din[-1:0];
end
endgenerate

endmodule
